def min_time_to_revert(word: str, k: int) -> int:
    n = len(word)
    for t in range(1, n + 1):
        if (t * k) % n == 0:
            shifted = word[(t * k) % n:] + word[:(t * k) % n]
            if shifted == word:
                return t
    return n
